function extractImageUrls(text) {
  if (!text || typeof text !== 'string') return [];

  // Regex to capture src="..." or src='...'
  const imgSrcRegex = /<img[^>]+src\s*=\s*["']([^"']+)["']/gi;

  const urls = new Set();
  let match;

  while ((match = imgSrcRegex.exec(text)) !== null) {
    urls.add(match[1]);
  }

  return Array.from(urls);
}
