function getValidJsonObject(rawText) {

    if (typeof rawText !== 'string' || rawText.trim() === '') {
        console.error("Invalid input or empty text field.");
        return null;
    }

    let jsonString = rawText.trim();

    // 2. Check for and remove the markdown JSON block fences.
    // This regex is robust and handles variations in whitespace.
    const markdownRegex = /^```json\s*([\s\S]*?)\s*```$/;
    const match = jsonString.match(markdownRegex);

    if (match) {
        // If it's a match, the actual JSON string is in the first capture group.
        jsonString = match[1];
    }

    // 3. Parse the cleaned string into a JSON object.
    try {
        return JSON.parse(jsonString);
    } catch (error) {
        console.error("Failed to parse JSON string:", error);
        console.error("Problematic string:", jsonString);
        return null;
    }
}
let result = getValidJsonObject($input.first().json.content.parts[0].text); 
if (typeof result !== 'undefined' && typeof result.image !== 'undefined' && typeof result.image.relevantImg !== 'undefined' && result.image.relevantImg !== null) {
  let relevantImage = [];
  let tempImg = [];
  for (const item of result.image.relevantImg) {
    if (item.url.includes("https://temp.com/")) {
      tempImg.push(item);
    }else{
      relevantImage.push(item);
    }
  }
  if(tempImg.length){
    let parsed = $('get Image Vault').first().json.parsed;
    let baseTempImg = [];
    for (const itemParsed of parsed) {
        let bufferObj = Buffer.from(itemParsed.title, "utf8");

      // Encode the buffer as a base64 string
      let base64String = bufferObj.toString("base64");
      let compare = 'https://temp.com/'+base64String+'.jpg';
       for (const itemTemp of tempImg) {
        if(itemTemp.url === compare ){
          baseTempImg.push({
            image: itemParsed.data,
            mime: itemParsed.mime
          })
        }
      } 
    }
    if(baseTempImg.length){
      result.image.tempImg = baseTempImg;  
    }else{
      result.image.tempImg = 'nope'; 
    }

  }else{
    result.image.tempImg = 'nope';
  }
  if(relevantImage.length){
    result.image.relevantImg = relevantImage;
  }else{
    result.image.relevantImg = [{url:'nope'}];  
  }
}else{
  result.image.relevantImg = [{url:'nope'}];
}
if (result && typeof result.content === 'string') {
  result.content = result.content.replace(
    /<img[^>]+src=["']https:\/\/temp\.com\/[^"']+["'][^>]*>/gi,
    ''
  );
}
return result;

const prompt = $('Code in JavaScript2').first().json.image.prompt;

// Prepare the parts array with the text prompt first
const parts = [
  { text: prompt }
];

// Loop through all incoming items and extract images
// Note: If all images are in one item as different binary keys, adjust the loop.
// This assumes multiple items (e.g., 3 separate image items).

for (const item of $input.first().json.image ) {
  if (typeof item.mime !== 'undefined' && item.mime !== null) {
    parts.push({
        inlineData: {
          mimeType: item.mime,
          data: item.image // n8n already provides this as base64
        }
      });
  }
}
const tempImg = $('Code in JavaScript2').first().json.image.tempImg;
if( tempImg !== 'nope'){
  for (const item of tempImg ) {

  parts.push({
      inlineData: {
        mimeType: item.mime,
        data: item.image // n8n already provides this as base64
      }
    });

}
}

// Return the structure ready for the API
return {
  json: {
    payload: {
      contents: [
        {
          parts: parts
        }
      ],
      generationConfig: {
          responseModalities: ["image"],
          topP: 0.2,
          imageConfig:{
               aspectRatio: "16:9",
            "imageSize": "1K"
          }
      }
    }
  }
};
